```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

// Helper function to get table type from table name
template<typename T>
struct TableTypeHolder {};

inline const auto table_mapping = std::map<std::string, TableTypeHolder<>>{
    {"Student", TableTypeHolder<Student>{}},
    {"Course", TableTypeHolder<Course>{}},
    {"Score", TableTypeHolder<Score>{}},
    {"Major", TableTypeHolder<Major>{}}
};

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
    // Get the table type from the mapping
    auto it = table_mapping.find(table_name);
    if (it == table_mapping.end()) {
        throw std::runtime_error("Unknown table: " + table_name);
    }

    // Connect to database
    auto conn = sqlgen::sqlite::connect(db_path).value();

    // Use sqlgen's insert functionality
    sqlgen::insert(records)(conn).value();
}

void modify_eas_records_by_id(const std::string& table_name,
                              const int& record_id,
                              const std::string& col_name,
                              const auto& new_value) {
    // Get the table type from the mapping
    auto it = table_mapping.find(table_name);
    if (it == table_mapping.end()) {
        throw std::runtime_error("Unknown table: " + table_name);
    }

    using TableType = typename decltype(it->second)::Type;

    // Connect to database
    auto conn = sqlgen::sqlite::connect(db_path).value();

    // Build update statement using sqlgen's update functionality
    auto update_stmt = sqlgen::update<TableType>(
        sqlgen::col<col_name>.set(new_value)
    ) | sqlgen::where(sqlgen::col<"id"> == record_id);

    update_stmt(conn).value();
}

void delete_eas_records_by_id(const std::string& table_name,
                              const std::string& record_id) {
    // Get the table type from the mapping
    auto it = table_mapping.find(table_name);
    if (it == table_mapping.end()) {
        throw std::runtime_error("Unknown table: " + table_name);
    }

    using TableType = typename decltype(it->second)::Type;

    // Connect to database
    auto conn = sqlgen::sqlite::connect(db_path).value();

    // Build delete statement using sqlgen's delete_from functionality
    auto delete_stmt = sqlgen::delete_from<TableType> | 
                       sqlgen::where(sqlgen::col<"id"> == record_id);

    delete_stmt(conn).value();
}
```

## Key Implementation Details:

1. **Database Connection**: Uses `sqlgen::sqlite::connect(db_path)` to establish connection to the EAS database.

2. **Table Mapping**: Creates a mapping from table names to their corresponding struct types using `table_mapping`.

3. **Insert Function** (`add_eas_records`):
   - Uses `sqlgen::insert(records)` to insert the records
   - Leverages sqlgen's automatic table detection from the struct type

4. **Update Function** (`modify_eas_records_by_id`):
   - Uses `sqlgen::update<TableType>()` with `sqlgen::col<col_name>.set(new_value)`
   - Applies where condition with `sqlgen::where(sqlgen::col<"id"> == record_id)`
   - Uses the pipe operator `|` to chain conditions

5. **Delete Function** (`delete_eas_records_by_id`):
   - Uses `sqlgen::delete_from<TableType>` combined with `sqlgen::where()`
   - Implements the deletion with proper condition chaining

6. **Error Handling**: Includes basic error checking for unknown table names.

The implementation follows sqlgen's fluent API pattern and leverages the library's type-safe database operations as specified in the reference materials.

