  if (!read_result) {
    return false; // Read operation failed
  }

  auto read_items = *read_result;

  // Verify that the number of items matches
  if (items.size() != read_items.size()) {
    return false;
  }

  // Verify each item's data matches
  for (size_t i = 0; i < items.size(); ++i) {
