    | sqlgen::select_from<User>("u1"_t1, "u1.username"_t1, "u2.username"_t1, sqlgen::count("f1.user_id2"_t1).as<"mutual_count">)
    | sqlgen::inner_join<Friendship>("f1"_t2, "u1.user_id"_t1 == "f1.user_id1"_t2)
    | sqlgen::inner_join<Friendship>("f2"_t3, "f1.user_id2"_t2 == "f2.user_id1"_t3)
    | sqlgen::inner_join<User>("u2"_t4, "f2.user_id2"_t3 == "u2.user_id"_t4)
    | sqlgen::where("u1.user_id"_t1 < "u2.user_id"_t4 && sqlgen::exists(
        sqlgen::select_from<Friendship>("f3"_t5, "f3.user_id1"_t5, "f3.user_id2"_t5)
        .where("f3.user_id1"_t5 == "u1.user_id"_t1 && "f3.user_id2"_t5 == "u2.user_id"_t4)
      ))
    | sqlgen::group_by("u1.user_id"_t1, "u2.user_id"_t4)
    | sqlgen::having(sqlgen::count("f1.user_id2"_t1) > 0);

  // Query 2: Users with more than N friends using nested query
