    | sqlgen::select_from<User>("u1"_t1, "u1.username"_t1, "u2.username"_t2, "mf.username"_t3)
    | sqlgen::inner_join<Friendship>("f1"_t4, "u1.user_id"_t1 == "f1.user_id1"_t4)
    | sqlgen::inner_join<Friendship>("f2"_t5, "f1.user_id2"_t4 == "f2.user_id1"_t5)
    | sqlgen::inner_join<User>("u2"_t2, "f2.user_id2"_t5 == "u2.user_id"_t2)
