    | sqlgen::select_from<User>("u"_t1, "u.username"_t1, sqlgen::count("f.user_id2"_t2).as<"friend_count">)
    | sqlgen::left_join<Friendship>("f"_t2, "u.user_id"_t1 == "f.user_id1"_t2)
    | sqlgen::group_by("u.user_id"_t1, "u.username"_t1)
    | sqlgen::order_by(sqlgen::count("f.user_id2"_t2).desc());

