```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace analyze_department_employees {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string department_name;
  std::string location;
};

struct Employee {
  sqlgen::PrimaryKey<int> employee_id;
  int department_id;
  std::string first_name;
  std::string last_name;
  double salary;
};

struct JoinResult {
  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen::literals;

  // 1. Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite").value();

  // 2. Create tables and insert data
  sqlgen::write(conn, depts);
  sqlgen::write(conn, emps);

  // Helper function to execute join queries
  auto execute_join = [](auto query) {
    return query(conn).value();
  };

  // 3. Perform INNER JOIN
  auto inner_query = sqlgen::select_from<Department, "d">(
      "department_name"_d,
      "first_name"_e,
      "last_name"_e, 
      "salary"_e
    ) | sqlgen::inner_join<Employee, "e">("department_id"_d == "department_id"_e);

  // 4. Perform LEFT JOIN
  auto left_query = sqlgen::select_from<Employee, "e">(
      "department_name"_d,
      "first_name"_e,
      "last_name"_e,
      "salary"_e
    ) | sqlgen::left_join<Department, "d">("department_id"_e == "department_id"_d);

  // 5. Perform RIGHT JOIN
  auto right_query = sqlgen::select_from<Employee, "e">(
      "department_name"_d,
      "first_name"_e,
      "last_name"_e,
      "salary"_e
    ) | sqlgen::right_join<Department, "d">("department_id"_e == "department_id"_d);

  // 6. Perform FULL JOIN
  auto full_query = sqlgen::select_from<Employee, "e">(
      "department_name"_d,
      "first_name"_e,
      "last_name"_e,
      "salary"_e
    ) | sqlgen::full_join<Department, "d">("department_id"_e == "department_id"_d);

  // 7. Execute all queries and populate JoinAnalysis
  JoinAnalysis analysis;
  analysis.inner_join_results = execute_join(inner_query);
  analysis.left_join_results = execute_join(left_query);
  analysis.right_join_results = execute_join(right_query);
  analysis.full_join_results = execute_join(full_query);

  return analysis;
}

}  // namespace analyze_department_employees
```

## Key Implementation Details:

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to establish connection
2. **Table Creation & Data Insertion**: Uses `sqlgen::write()` to automatically create tables and insert data based on the provided structs
3. **Join Operations**: Implements all four join types using sqlgen's fluent API:
   - INNER JOIN: `sqlgen::inner_join<Table, Alias>(condition)`
   - LEFT JOIN: `sqlgen::left_join<Table, Alias>(condition)`
   - RIGHT JOIN: `sqlgen::right_join<Table, Alias>(condition)`
   - FULL JOIN: `sqlgen::full_join<Table, Alias>(condition)`
4. **Column References**: Uses string literals with table aliases (`"department_name"_d`, `"first_name"_e`) to reference columns
5. **Join Conditions**: Uses equality comparison (`==`) to define join conditions between department_id fields
6. **Result Collection**: Executes each query and populates the corresponding vector in `JoinAnalysis`

The implementation follows sqlgen's principles of using compile-time type safety and fluent API design while meeting all the specified requirements for join operations and result analysis.

